import{_ as e,o as a,c as l,a2 as s}from"./chunks/framework.CMAFtOGK.js";const c=JSON.parse('{"title":"阅读理解高分技巧","description":"公共英语 · 阅读理解高分技巧","frontmatter":{"title":"阅读理解高分技巧","description":"公共英语 · 阅读理解高分技巧","category":"english-note"},"headers":[],"relativePath":"posts/english/notes/reading.md","filePath":"posts/english/notes/reading.md","lastUpdated":1784747786000}'),n={name:"posts/english/notes/reading.md"};function i(r,t,o,d,p,h){return a(),l("div",null,[...t[0]||(t[0]=[s(`<h1 id="📖-阅读理解高分技巧" tabindex="-1">📖 阅读理解高分技巧 <a class="header-anchor" href="#📖-阅读理解高分技巧" aria-label="Permalink to &quot;📖 阅读理解高分技巧&quot;">​</a></h1><blockquote><p>专升本英语阅读 | 六大题型 | 解题套路</p></blockquote><hr><h2 id="一、题型统计" tabindex="-1">一、题型统计 <a class="header-anchor" href="#一、题型统计" aria-label="Permalink to &quot;一、题型统计&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">题型</th><th style="text-align:center;">占比</th><th style="text-align:center;">难度</th></tr></thead><tbody><tr><td style="text-align:left;">🔍 细节理解题</td><td style="text-align:center;">~40%</td><td style="text-align:center;">⭐ 易</td></tr><tr><td style="text-align:left;">🎯 推理判断题</td><td style="text-align:center;">~20%</td><td style="text-align:center;">⭐⭐⭐ 难</td></tr><tr><td style="text-align:left;">📌 主旨大意题</td><td style="text-align:center;">~15%</td><td style="text-align:center;">⭐⭐ 中</td></tr><tr><td style="text-align:left;">🔤 词义猜测题</td><td style="text-align:center;">~15%</td><td style="text-align:center;">⭐⭐ 中</td></tr><tr><td style="text-align:left;">💭 观点态度题</td><td style="text-align:center;">~10%</td><td style="text-align:center;">⭐⭐ 中</td></tr></tbody></table><hr><h2 id="二、六大题型破解" tabindex="-1">二、六大题型破解 <a class="header-anchor" href="#二、六大题型破解" aria-label="Permalink to &quot;二、六大题型破解&quot;">​</a></h2><h3 id="_1️⃣-细节理解题-40" tabindex="-1">1️⃣ 细节理解题（40%） <a class="header-anchor" href="#_1️⃣-细节理解题-40" aria-label="Permalink to &quot;1️⃣ 细节理解题（40%）&quot;">​</a></h3><p><strong>常见问法：</strong></p><ul><li>According to the passage, ...</li><li>What is mentioned about ...?</li><li>Which of the following is TRUE/NOT true?</li></ul><p><strong>解题步骤：</strong></p><ol><li>题干中找关键词（专有名词、数字、大写词）</li><li>用关键词<strong>回原文定位</strong></li><li>对比选项和原文，选同义替换的项</li></ol><blockquote><p>⚠️ <strong>干扰项特征：</strong> 张冠李戴、偷换概念、过度推断、与原文相反</p></blockquote><h3 id="_2️⃣-推理判断题-20" tabindex="-1">2️⃣ 推理判断题（20%） <a class="header-anchor" href="#_2️⃣-推理判断题-20" aria-label="Permalink to &quot;2️⃣ 推理判断题（20%）&quot;">​</a></h3><p><strong>常见问法：</strong></p><ul><li>It can be inferred from the passage that...</li><li>The author implies/suggests that...</li><li>What can we learn from the passage?</li></ul><p><strong>解题要点：</strong></p><ul><li>✅ 基于原文逻辑合理推断</li><li>❌ 不要过度发挥（原文没说的不能选）</li><li>❌ 不要选原文<strong>直接陈述</strong>的内容</li></ul><blockquote><p><strong>口诀：</strong> 推断题选&quot;可能但不肯定&quot;的，不选&quot;原文直接说的&quot;</p></blockquote><h3 id="_3️⃣-主旨大意题-15" tabindex="-1">3️⃣ 主旨大意题（15%） <a class="header-anchor" href="#_3️⃣-主旨大意题-15" aria-label="Permalink to &quot;3️⃣ 主旨大意题（15%）&quot;">​</a></h3><p><strong>常见问法：</strong></p><ul><li>What is the main idea of the passage?</li><li>The best title for the passage would be...</li><li>What is the passage mainly about?</li></ul><p><strong>解题步骤：</strong></p><ol><li>读<strong>首段首尾句 + 每段首句</strong></li><li>找<strong>主题句</strong>（通常在开头或结尾）</li><li>排除以偏概全、过于宽泛的选项</li></ol><h3 id="_4️⃣-词义猜测题-15" tabindex="-1">4️⃣ 词义猜测题（15%） <a class="header-anchor" href="#_4️⃣-词义猜测题-15" aria-label="Permalink to &quot;4️⃣ 词义猜测题（15%）&quot;">​</a></h3><p><strong>常见问法：</strong></p><ul><li>The word &quot;...&quot; in paragraph X probably means...</li><li>Which of the following can replace &quot;...&quot;?</li></ul><p><strong>猜词技巧：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">线索类型</th><th style="text-align:left;">标志词</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;">定义法</td><td style="text-align:left;">is, means, refers to</td><td style="text-align:left;">A <strong>habitat</strong> is the natural home of an animal.</td></tr><tr><td style="text-align:left;">对比法</td><td style="text-align:left;">but, however, while, unlike</td><td style="text-align:left;">Unlike his <strong>generous</strong> brother, he is very stingy.</td></tr><tr><td style="text-align:left;">因果法</td><td style="text-align:left;">because, so, since, thus</td><td style="text-align:left;">He was so <strong>exhausted</strong> that he fell asleep immediately.</td></tr><tr><td style="text-align:left;">举例法</td><td style="text-align:left;">such as, for example, like</td><td style="text-align:left;"><strong>Carnivores</strong>, such as lions and tigers, eat meat.</td></tr><tr><td style="text-align:left;">同义法</td><td style="text-align:left;">or, that is, i.e.</td><td style="text-align:left;">The <strong>adversary</strong>, or opponent, was strong.</td></tr></tbody></table><h3 id="_5️⃣-观点态度题-10" tabindex="-1">5️⃣ 观点态度题（10%） <a class="header-anchor" href="#_5️⃣-观点态度题-10" aria-label="Permalink to &quot;5️⃣ 观点态度题（10%）&quot;">​</a></h3><p><strong>常见问法：</strong></p><ul><li>What is the author&#39;s attitude towards...?</li><li>The tone of the passage is...</li></ul><p><strong>态度词库：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">正向</th><th style="text-align:left;">负向</th><th style="text-align:left;">中立</th></tr></thead><tbody><tr><td style="text-align:left;">positive</td><td style="text-align:left;">negative</td><td style="text-align:left;">neutral</td></tr><tr><td style="text-align:left;">supportive</td><td style="text-align:left;">critical</td><td style="text-align:left;">objective</td></tr><tr><td style="text-align:left;">optimistic</td><td style="text-align:left;">pessimistic</td><td style="text-align:left;">impartial</td></tr><tr><td style="text-align:left;">favorable</td><td style="text-align:left;">disapproving</td><td style="text-align:left;">indifferent</td></tr></tbody></table><blockquote><p>🚨 <strong>小炸弹：</strong> indifferent（漠不关心的）几乎永远不选——作者写一篇文章不可能漠不关心</p></blockquote><hr><h2 id="三、长难句分析" tabindex="-1">三、长难句分析 <a class="header-anchor" href="#三、长难句分析" aria-label="Permalink to &quot;三、长难句分析&quot;">​</a></h2><h3 id="三步拆解" tabindex="-1">三步拆解 <a class="header-anchor" href="#三步拆解" aria-label="Permalink to &quot;三步拆解&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Step 1: 找谓语动词 → 确定有几个句子</span></span>
<span class="line"><span>Step 2: 找连词/关系词 → 分清主从句</span></span>
<span class="line"><span>Step 3: 去修饰留主干 → 主谓宾即核心</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="实战演练" tabindex="-1">实战演练 <a class="header-anchor" href="#实战演练" aria-label="Permalink to &quot;实战演练&quot;">​</a></h3><blockquote><p><strong>原句：</strong> The study, <em>which was conducted by researchers from Harvard University</em>, found that students who <strong>regularly participated in physical exercise</strong> performed better on exams.</p></blockquote><ul><li><strong>主干：</strong> The study found that students performed better on exams.</li><li><strong>修饰1：</strong> which was conducted by...（定语从句，修饰study）</li><li><strong>修饰2：</strong> who regularly participated...（定语从句，修饰students）</li></ul><hr><h2 id="四、时间分配策略" tabindex="-1">四、时间分配策略 <a class="header-anchor" href="#四、时间分配策略" aria-label="Permalink to &quot;四、时间分配策略&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>文章阅读量：4篇 × 300-400词 = 1200-1600词</span></span>
<span class="line"><span>总用时：40分钟</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────┐</span></span>
<span class="line"><span>│ 通读全文划关键 → 5min/篇      │</span></span>
<span class="line"><span>│ 逐题定位找依据 → 4min/篇      │</span></span>
<span class="line"><span>│ 填涂检查 → 1min/篇           │</span></span>
<span class="line"><span>│                              │</span></span>
<span class="line"><span>│ 每篇总计：10分钟              │</span></span>
<span class="line"><span>│ 四篇总计：40分钟              │</span></span>
<span class="line"><span>└─────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><hr><h2 id="五、高频干扰项特征" tabindex="-1">五、高频干扰项特征 <a class="header-anchor" href="#五、高频干扰项特征" aria-label="Permalink to &quot;五、高频干扰项特征&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">干扰类型</th><th style="text-align:left;">特征</th><th style="text-align:left;">识别方法</th></tr></thead><tbody><tr><td style="text-align:left;">偷换概念</td><td style="text-align:left;">用原文某词造个不同意思的句子</td><td style="text-align:left;">逐字比对</td></tr><tr><td style="text-align:left;">张冠李戴</td><td style="text-align:left;">A的事说成B的</td><td style="text-align:left;">注意主语对应</td></tr><tr><td style="text-align:left;">过度推断</td><td style="text-align:left;">推到了原文没说的一步</td><td style="text-align:left;">回到原文看能否推出</td></tr><tr><td style="text-align:left;">以偏概全</td><td style="text-align:left;">局部当整体</td><td style="text-align:left;">看选项范围是否太大</td></tr><tr><td style="text-align:left;">正反混淆</td><td style="text-align:left;">与原文意思相反</td><td style="text-align:left;">注意否定词</td></tr></tbody></table><hr><h2 id="秒杀口诀" tabindex="-1">秒杀口诀 <a class="header-anchor" href="#秒杀口诀" aria-label="Permalink to &quot;秒杀口诀&quot;">​</a></h2><blockquote><p><strong>细节定位找替换，推断两选选弱的那一个</strong><strong>主旨看首段，猜词看上下文</strong><strong>态度题excited/surprised别乱选，客观中立最安全</strong><strong>长难句三步走：找谓、分清、留主干</strong></p></blockquote><p>[VOICE: 阅读理解占30分是试卷的大头，关键是学会定位和排除干扰项，细节题考最多，靠关键词回原文定位找同义替换就行！]</p>`,52)])])}const u=e(n,[["render",i]]);export{c as __pageData,u as default};
